# T-28: Chart.js Dashboard Analytics

Using z-ai/glm-5.1 on EastRouter for execution.

---

## What I Did

### 1. Backend: Analytics Controller &amp; Endpoint

**`app/Http/Controllers/Api/DashboardAnalyticsController.php`**
```php
&lt;?php

namespace App\Http\Controllers\Api;

use App\Http\Controllers\Controller;
use App\Models\Ticket;
use Illuminate\Http\JsonResponse;

class DashboardAnalyticsController extends Controller
{
    public function __invoke(): JsonResponse
    {
        return response()-&gt;json([
            'ticket_volume' =&gt; $this-&gt;ticketVolume(),
            'by_status'     =&gt; $this-&gt;byStatus(),
            'by_priority'   =&gt; $this-&gt;byPriority(),
            'resolution'    =&gt; $this-&gt;resolutionRate(),
        ]);
    }

    private function ticketVolume(): array
    {
        return Ticket::query()
            -&gt;selectRaw("DATE(created_at) as date, COUNT(*) as count")
            -&gt;where('created_at', '&gt;=', now()-&gt;subDays(30))
            -&gt;groupByRaw('DATE(created_at)')
            -&gt;orderBy('date')
            -&gt;get()
            -&gt;map(fn ($row) =&gt; [
                'date'  =&gt; $row-&gt;date,
                'count' =&gt; (int) $row-&gt;count,
            ])
            -&gt;toArray();
    }

    private function byStatus(): array
    {
        return Ticket::query()
            -&gt;selectRaw('status, COUNT(*) as count')
            -&gt;groupBy('status')
            -&gt;pluck('count', 'status')
            -&gt;toArray();
    }

    private function byPriority(): array
    {
        return Ticket::query()
            -&gt;selectRaw('priority, COUNT(*) as count')
            -&gt;groupBy('priority')
            -&gt;pluck('count', 'priority')
            -&gt;toArray();
    }

    private function resolutionRate(): array
    {
        $total = Ticket::count();
        $resolved = Ticket::where('status', 'resolved')-&gt;count();

        return [
            'total'    =&gt; $total,
            'resolved' =&gt; $resolved,
            'rate'     =&gt; $total &gt; 0 ? round(($resolved / $total) * 100, 1) : 0,
        ];
    }
}
```

**`routes/api.php`** (added route)
