    Ticket::factory()-&gt;count(3)-&gt;create(['status' =&gt; 'resolved', 'priority' =&gt; 'low']);

    $this-&gt;actingAs($user, 'sanctum')
        -&gt;getJson('/api/analytics/dashboard')
