    $user = User::factory()-&gt;create();

    $this-&gt;actingAs($user, 'sanctum')
        -&gt;getJson('/api/analytics/dashboard')
        -&gt;assertOk()
        -&gt;assertJsonPath('resolution.rate', 0);
});
