import { useEffect, useRef } from 'react';
import {
  Chart,
  LineController,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  DoughnutController,
  ArcElement,
  Tooltip,
  Legend,
} from 'chart.js';

Chart.register(
  LineController,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  DoughnutController,
  ArcElement,
  Tooltip,
  Legend,
);

type VolumePoint = { date: string; count: number };
type Analytics = {
  ticket_volume: VolumePoint[];
  by_status: Record<string, number>;

text:
  by_priority: Record&lt;string, number&gt;;
  resolution: { total: number; resolved: number; rate: number };
};

export default function AnalyticsDashboard() {
  const lineRef = useRef&lt;HTMLCanvasElement&gt;(null);
  const doughnutRef = useRef&lt;HTMLCanvasElement&gt;(null);
  const charts = useRef&lt;Chart[]&gt;([]);

  useEffect(() =&gt; {
    fetch('/api/analytics/dashboard', {
      headers: {
        Authorization: `Bearer ${localStorage.getItem('token')}`,
        Accept: 'application/json',
      },
    })
      .then((res) =&gt; res.json())
      .then((data: Analytics) =&gt; {
        // Line chart — ticket volume
        if (lineRef.current) {
          charts.current.push(
            new Chart(lineRef.current, {
              type: 'line',
              data: {
                labels: data.ticket_volume.map((p) =&gt; p.date),
                datasets: [
                  {
                    label: 'Ticket Volume',
                    data: data.ticket_volume.map((p) =&gt; p.count),
                    borderColor: '#6366f1',
                    tension: 0.3,
                    fill: false,
                  },
                ],
              },
              options: {
                responsive: true,
                plugins: { tooltip: { mode: 'index' } },
              },
            }),
          );
        }

        // Doughnut chart — by status
        if (doughnutRef.current) {
          charts.current.push(
            new Chart(doughnutRef.current, {
              type: 'doughnut',
              data: {
                labels: Object.keys(data.by_status),
                datasets: [
                  {
                    data: Object.values(data.by_status),
                    backgroundColor: ['#6366f1', '#10b981', '#f59e0b', '#ef4444'],
                  },
                ],
              },
              options: { responsive: true, plugins: { legend: { position: 'right' } } },
            }),
          );
        }
      });

    return () =&gt; charts.current.forEach((c) =&gt; c.destroy());
  }, []);

  return (
    &lt;div className="grid grid-cols-1 gap-6 lg:grid-cols-2"&gt;
      &lt;div className="rounded-xl bg-white p-6 shadow-sm"&gt;
        &lt;h3 className="mb-4 text-sm font-semibold text-gray-700"&gt;Ticket Volume (30d)&lt;/h3&gt;
        &lt;canvas ref={lineRef} /&gt;
      &lt;/div&gt;
      &lt;div className="rounded-xl bg-white p-6 shadow-sm"&gt;
        &lt;h3 className="mb-4 text-sm font-semibold text-gray-700"&gt;Tickets by Status&lt;/h3&gt;
        &lt;canvas ref={doughnutRef} /&gt;
      &lt;/div&gt;
    &lt;/div&gt;
  );
}
